    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryLabels = [];

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void TrainModel()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',',
            allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Extract category labels from the trained model's key-value mapping
        var labelCol = dataView.Schema[nameof(TicketData.Category)];
        var keyCol = _model.GetOutputSchema(dataView.Schema)["Label"];
        var keyType = keyCol.Type as Microsoft.ML.Data.KeyDataViewType;

        VBuffer<ReadOnlyMemory<char>> keys = default;
        _model.GetOutputSchema(dataView.Schema)["Label"]
            .GetKeyValues(ref keys);
        _categoryLabels = keys.DenseValues()
            .Select(v => v.ToString()).ToArray();

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
    }

    public EvaluationResponse Evaluate()
    {
        if (_model is null)
            throw new InvalidOperationException(
                "Model must be trained before evaluation.");

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',',
            allowQuoting: true);

        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification
            .Evaluate(predictions, "Label");

        var perClass = metrics.PerClassLogLoss
            .Select((_, i) => new PerClassPrecisionRecall(
                i < _categoryLabels.Length ? _categoryLabels[i] : $"Class{i}",
                i < metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                i < metrics.ConfusionMatrix.PerClassRecall.Count
                    ? metrics.ConfusionMatrix.PerClassRecall[i] : 0))
            .ToArray();

        return new EvaluationResponse(
            MacroAccuracy: metrics.MacroAccuracy,
            MicroAccuracy: metrics.MicroAccuracy,
            LogLoss: metrics.LogLoss,
            LogLossReduction: metrics.LogLossReduction,
            PerClassMetrics: perClass);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException(
                "Model must be trained before prediction.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length; i++)
        {
            var label = i < _categoryLabels.Length
                ? _categoryLabels[i] : $"Class{i}";
            confidence[label] = prediction.Score[i];
        }

        return new PredictionResponse(
            prediction.PredictedCategory, confidence);
    }
}

