using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketClassifierService service) : ControllerBase
{
    [HttpPost("train")]
    public IActionResult Train()
    {
        service.TrainModel();
        return Ok(new { message = "Model trained successfully." });
    }

    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        if (!service.IsModelTrained)
            return BadRequest(new { error = "Train the model first via POST /api/ticketclassifier/train." });

        return Ok(service.Evaluate());
    }

    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        if (!service.IsModelTrained)
            return BadRequest(new { error = "Train the model first via POST /api/ticketclassifier/train." });

        if (request.Priority is < 1 or > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        return Ok(service.Predict(request));
    }
}

